import React, { useState } from 'react';
import './App.css';
import Header from './components/header/header';
import navigationValues from './navList';

// Create a navigation context with a default of home
const navigationContext = React.createContext(navigationValues.home);

function App() {
  const [nav, setNav] = useState(navigationValues.home);
  return (
    <>
      <navigationContext.Provider value={nav}>
        <Header/>      
      </navigationContext.Provider>
    </>
  );
}

// Export the context as we want it to be available in child components.
export {navigationContext};
export default App;
